    message = "Confidential data: the answer is 42."

    # 3️⃣ Encrypt
    try:
        ct, nonce, tag = encrypt(key, message)
        print("Encryption succeeded.")
        print(f"Ciphertext (hex): {ct.hex()}")
        print(f"Nonce (hex)      : {nonce.hex()}")
        print(f"Tag (hex)        : {tag.hex()}")
    except Exception as e:
        print(f"Encryption failed: {e}")

    # 4️⃣ Decrypt – normal case
    try:
        recovered = decrypt(key, ct, nonce, tag)
        print("\nDecryption succeeded.")
        print(f"Recovered plaintext: {recovered}")
    except InvalidTag:
        print("\nDecryption failed: authentication tag verification error.")
    except Exception as e:
        print(f"\nDecryption failed with unexpected error: {e}")

    # 5️⃣ Decrypt – tampered ciphertext (demonstrates exception handling)
